public static long solve(long[] value, long[] limit) {
    int n = value.length;
    Integer[] indices = new Integer[n];
    for (int i = 0; i < n; i++) {
        indices[i] = i;
    }

    // Sort indices based on limit in ascending order, then by value in descending order
    Arrays.sort(indices, new Comparator<Integer>() {
        public int compare(Integer a, Integer b) {
            if (limit[a] != limit[b]) {
                return Long.compare(limit[a], limit[b]);
            } else {
                return Long.compare(value[b], value[a]);
            }
        }
    });

    long total = 0;
    long active = 0;

    for (int i = 0; i < n; ) {
        long currentLimit = limit[indices[i]];
        // The maximum number of elements we can take before active >= currentLimit is currentLimit - 1 - active
        // But since we are processing in order, we can take all elements with limit > active until active reaches currentLimit - 1
        // So we can take all elements with limit > active, but we need to process them in batches of same limit

        // Find the end of the current batch (elements with same limit)
        int j = i;
        while (j < n && limit[indices[j]] == currentLimit) {
            j++;
        }

        // The number of elements we can take from this batch is min(j - i, currentLimit - 1 - active)
        long canTake = Math.min(j - i, currentLimit - 1 - active);
        if (canTake <= 0) {
            // No elements can be taken from this batch, move to next batch
            i = j;
            continue;
        }

        // Now, we need to take top 'canTake' elements from this batch (they are already sorted by value descending)
        for (int k = i; k < i + canTake; k++) {
            total += value[indices[k]];
            active++;
        }

        // After taking these elements, active may reach currentLimit - 1
        // Now, when we take the next element, active will become currentLimit, and all elements with limit <= currentLimit will be deactivated
        // So we can't take any more elements with limit <= currentLimit
        // So we can skip all remaining elements with limit <= currentLimit
        i = j;
    }

    return total;
}
