    }

    // Sort indices based on value in descending order
    Collections.sort(indices, (a, b) -> Long.compare(value[b], value[a]));

    long total = 0;
    int active = 0;
    boolean[] isActive = new boolean[n];

    for (int i : indices) {
        if (!isActive[i] && active < limit[i]) {
            total += value[i];
            isActive[i] = true;
            active++;

            // Deactivate elements where limit[j] <= active
            for (int j = 0; j < n; j++) {
                if (isActive[j] && limit[j] <= active) {
                    isActive[j] = false;
                    active--;
                }
            }
        }
    }

    return total;
